import{_ as a,o as i,c as t,ag as o}from"./chunks/framework.CAXxHpAX.js";const c=JSON.parse('{"title":"什么是 API Key","description":"","frontmatter":{},"headers":[],"relativePath":"guide/api-key.md","filePath":"guide/api-key.md"}'),l={name:"guide/api-key.md"};function r(p,e,n,s,d,h){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="什么是-api-key" tabindex="-1">什么是 API Key <a class="header-anchor" href="#什么是-api-key" aria-label="Permalink to &quot;什么是 API Key&quot;">​</a></h1><p>API Key 是用于身份验证的密钥,相当于你的&quot;用户名 + 密码&quot;。当你调用一个 API 时,服务器通过 API Key 识别你是谁、是否有权限访问。</p><h2 id="为什么需要-api-key" tabindex="-1">为什么需要 API Key <a class="header-anchor" href="#为什么需要-api-key" aria-label="Permalink to &quot;为什么需要 API Key&quot;">​</a></h2><p>大多数 AI 编程工具都需要你提供一个 API Key,原因包括:</p><ul><li><strong>身份识别</strong>:服务器需要知道是谁在调用 API</li><li><strong>计费与限额</strong>:根据 API Key 统计使用量、控制配额</li><li><strong>安全控制</strong>:防止未授权访问</li></ul><h2 id="api-key-的常见形式" tabindex="-1">API Key 的常见形式 <a class="header-anchor" href="#api-key-的常见形式" aria-label="Permalink to &quot;API Key 的常见形式&quot;">​</a></h2><p>API Key 通常是一个长字符串,例如:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sk-ant-xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx</span></span></code></pre></div><p>不同服务商的 API Key 格式可能不同,但都遵循&quot;一个密钥对应一个身份&quot;的原则。</p><h2 id="如何获取-api-key" tabindex="-1">如何获取 API Key <a class="header-anchor" href="#如何获取-api-key" aria-label="Permalink to &quot;如何获取 API Key&quot;">​</a></h2><p>你需要从对应的服务商处获取 API Key。获取方式因服务商而异,通常需要:</p><ol><li>注册账号</li><li>进入控制台或设置页面</li><li>生成或复制 API Key</li></ol><p><strong>注意</strong>:API Key 是敏感信息,不要分享给他人,也不要提交到公开代码仓库。</p><h2 id="在工具中填写-api-key" tabindex="-1">在工具中填写 API Key <a class="header-anchor" href="#在工具中填写-api-key" aria-label="Permalink to &quot;在工具中填写 API Key&quot;">​</a></h2><p>不同工具填写 API Key 的位置不同,但通常在以下位置之一:</p><ul><li>设置面板的&quot;API Key&quot;字段</li><li>配置文件的 <code>apiKey</code> 字段</li><li>环境变量(如 <code>ANTHROPIC_API_KEY</code>)</li></ul><p>具体填写方式请参考对应工具的配置页面。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="api-key-填错了会怎样" tabindex="-1">API Key 填错了会怎样? <a class="header-anchor" href="#api-key-填错了会怎样" aria-label="Permalink to &quot;API Key 填错了会怎样?&quot;">​</a></h3><p>通常会返回 <code>401 Unauthorized</code> 错误,提示身份验证失败。</p><h3 id="api-key-泄露了怎么办" tabindex="-1">API Key 泄露了怎么办? <a class="header-anchor" href="#api-key-泄露了怎么办" aria-label="Permalink to &quot;API Key 泄露了怎么办?&quot;">​</a></h3><p>立即到服务商控制台撤销旧 Key,并生成新 Key。</p><h3 id="可以多个工具共用一个-api-key-吗" tabindex="-1">可以多个工具共用一个 API Key 吗? <a class="header-anchor" href="#可以多个工具共用一个-api-key-吗" aria-label="Permalink to &quot;可以多个工具共用一个 API Key 吗?&quot;">​</a></h3><p>可以,只要服务商允许。但要注意使用量会合并计算。</p>',24)])])}const x=a(l,[["render",r]]);export{c as __pageData,x as default};
